// Build a LinkedIn-ready post from the Google News RSS item
const item = $input.first().json;

const title = (item.title || '').split(' - ')[0].trim();
const link = item.link || '';
const sourceMatch = (item.title || '').match(/-\s*([^-]+)$/);
const source = sourceMatch ? sourceMatch[1].trim() : (item.creator || 'Google News');

const hashtags = '#Ecommerce #EcommerceMarket #RetailTech #OnlineShopping #MarketTrends';

const postText = `📊 E-commerce Market Update\n\n${title}\n\nSource: ${source}\nRead more: ${link}\n\n${hashtags}`;

return [{
  json: {
    postText,
    title,
    link,
    source,
    publishedAt: item.isoDate || item.pubDate || ''
  }
}];
